    if (nums.size() == 1) {
        return 0;
    }

    // Sort the array
    std::sort(nums.begin(), nums.end());

    // Use a sliding window to find the longest subarray that is balanced
    int left = 0;
    long long minRemovals = nums.size(); // Max possible removals

    for (int right = 0; right < nums.size(); ++right) {
        // Move left pointer until the window is balanced
        while (left < right && static_cast<long long>(nums[right]) > k * nums[left]) {
            left++;
